import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.C58al07P.js";const h=JSON.parse('{"title":"Paramètres","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/settings.md","filePath":"fr/guide/settings.md"}'),r={name:"fr/guide/settings.md"};function s(n,e,l,c,u,d){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="parametres" tabindex="-1">Paramètres <a class="header-anchor" href="#parametres" aria-label="Permalink to &quot;Paramètres&quot;">​</a></h1><p>La page <strong>Paramètres</strong> centralise la configuration de votre compte, la sécurité, les webhooks et les préférences.</p><hr><h2 id="profil" tabindex="-1">Profil <a class="header-anchor" href="#profil" aria-label="Permalink to &quot;Profil&quot;">​</a></h2><p>La section profil affiche vos informations :</p><ul><li><strong>Email</strong> : votre adresse email de connexion</li><li><strong>Nom d&#39;affichage</strong> : modifiable (récupéré automatiquement depuis Google SSO)</li><li><strong>Avatar</strong> : récupéré depuis Google SSO le cas échéant</li><li><strong>Rôle</strong> : Utilisateur ou Administrateur</li></ul><hr><h2 id="comptes-gmail-connectes" tabindex="-1">Comptes Gmail connectés <a class="header-anchor" href="#comptes-gmail-connectes" aria-label="Permalink to &quot;Comptes Gmail connectés&quot;">​</a></h2><p>Liste de tous vos comptes Gmail liés à Nid :</p><ul><li>Email de chaque compte</li><li>Statut de la connexion (actif / inactif)</li><li>Bouton <strong>Connecter un compte Gmail</strong> pour en ajouter un nouveau</li><li>Bouton <strong>Déconnecter</strong> pour retirer un compte</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : section Comptes Gmail avec la liste des comptes et les boutons connecter/déconnecter</em></p></blockquote><hr><h2 id="authentification-a-deux-facteurs-2fa" tabindex="-1">Authentification à deux facteurs (2FA) <a class="header-anchor" href="#authentification-a-deux-facteurs-2fa" aria-label="Permalink to &quot;Authentification à deux facteurs (2FA)&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Comptes locaux uniquement</p><p>La 2FA ne s&#39;applique qu&#39;aux comptes locaux (email + mot de passe). Les utilisateurs Google SSO sont protégés par la 2FA de Google.</p></div><h3 id="activer-la-2fa" tabindex="-1">Activer la 2FA <a class="header-anchor" href="#activer-la-2fa" aria-label="Permalink to &quot;Activer la 2FA&quot;">​</a></h3><ol><li>Cliquez sur <strong>Configurer la 2FA</strong></li><li>Un <strong>QR code</strong> s&#39;affiche</li><li>Scannez-le avec votre application d&#39;authentification (Google Authenticator, Authy, Microsoft Authenticator, etc.)</li><li>Saisissez le code à 6 chiffres affiché par l&#39;app</li><li>Cliquez sur <strong>Vérifier et activer</strong></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : QR code de configuration 2FA avec le champ de vérification du code</em></p></blockquote><h3 id="connexion-avec-2fa" tabindex="-1">Connexion avec 2FA <a class="header-anchor" href="#connexion-avec-2fa" aria-label="Permalink to &quot;Connexion avec 2FA&quot;">​</a></h3><p>Lors de la connexion, après avoir saisi votre email et mot de passe, un champ supplémentaire demande le code TOTP de votre application d&#39;authentification.</p><h3 id="desactiver-la-2fa" tabindex="-1">Désactiver la 2FA <a class="header-anchor" href="#desactiver-la-2fa" aria-label="Permalink to &quot;Désactiver la 2FA&quot;">​</a></h3><p>Cliquez sur <strong>Désactiver la 2FA</strong> et confirmez en saisissant un code TOTP valide.</p><hr><h2 id="preferences-de-notifications" tabindex="-1">Préférences de notifications <a class="header-anchor" href="#preferences-de-notifications" aria-label="Permalink to &quot;Préférences de notifications&quot;">​</a></h2><p>Tableau permettant de choisir, pour chaque type de notification, les canaux actifs (in-app et toast). Voir la page <a href="./notifications.html#préférences-de-notifications">Notifications</a> pour les détails.</p><hr><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Configuration des webhooks sortants. Voir la page <a href="./notifications.html#webhooks">Notifications — Webhooks</a> pour les détails.</p><hr><h2 id="export-import-de-configuration" tabindex="-1">Export / Import de configuration <a class="header-anchor" href="#export-import-de-configuration" aria-label="Permalink to &quot;Export / Import de configuration&quot;">​</a></h2><p>Sauvegardez et restaurez votre configuration (règles et webhooks) au format JSON.</p><h3 id="exporter" tabindex="-1">Exporter <a class="header-anchor" href="#exporter" aria-label="Permalink to &quot;Exporter&quot;">​</a></h3><ol><li>Cliquez sur <strong>Exporter</strong></li><li>Un fichier <code>nid-config.json</code> est téléchargé</li></ol><p>Le fichier contient vos règles (associées par email de compte Gmail) et vos webhooks. Les données sensibles (tokens, secrets) ne sont <strong>pas</strong> incluses.</p><h3 id="importer" tabindex="-1">Importer <a class="header-anchor" href="#importer" aria-label="Permalink to &quot;Importer&quot;">​</a></h3><ol><li>Cliquez sur <strong>Importer</strong></li><li>Sélectionnez un fichier JSON précédemment exporté</li><li>Les règles sont associées à vos comptes Gmail par correspondance d&#39;email</li><li>Les webhooks sont importés directement</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : section Export/Import avec les boutons Exporter et Importer</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Import additif</p><p>L&#39;import <strong>ajoute</strong> les éléments sans supprimer les existants. Importer plusieurs fois le même fichier créera des doublons.</p></div><hr><h2 id="journal-d-activite-audit-log" tabindex="-1">Journal d&#39;activité (Audit log) <a class="header-anchor" href="#journal-d-activite-audit-log" aria-label="Permalink to &quot;Journal d&#39;activité (Audit log)&quot;">​</a></h2><p>La section <strong>Journal d&#39;activité</strong> affiche vos dernières actions dans l&#39;application :</p><ul><li>Connexions et déconnexions</li><li>Créations, modifications et suppressions de règles</li><li>Opérations bulk (suppression, archivage)</li><li>Exports et imports de configuration</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : journal d&#39;activité avec les actions, dates et détails</em></p></blockquote><hr><h2 id="langue" tabindex="-1">Langue <a class="header-anchor" href="#langue" aria-label="Permalink to &quot;Langue&quot;">​</a></h2><p>Le sélecteur de langue est situé dans la <strong>barre de navigation</strong> (en haut), à côté de la cloche de notifications.</p><p>Langues disponibles :</p><ul><li>🇫🇷 Français (par défaut)</li><li>🇬🇧 Anglais</li></ul><p>Le choix est persisté dans le navigateur et conservé entre les sessions.</p><hr><h2 id="theme" tabindex="-1">Thème <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Thème&quot;">​</a></h2><p>Le toggle <strong>thème sombre / clair</strong> est situé dans la barre de navigation, à côté du sélecteur de langue. Le choix est persisté dans le navigateur.</p>',51)])])}const m=a(r,[["render",s]]);export{h as __pageData,m as default};
